mapper.select:
SELECT * FROM doctor_schedule
WHERE doctor_id = #{doctorId} AND schedule_date = #{scheduleDate}
ORDER BY time_slot

SELECT * FROM doctor_schedule
ORDER BY schedule_date DESC, time_slot
LIMIT #{start}, #{size}

SELECT ds.* FROM doctor_schedule ds LEFT JOIN doctor d ON ds.doctor_id = d.id WHERE 1=1
AND d.doctor_name LIKE CONCAT('%', #{doctorName}, '%')
AND ds.hospital_name LIKE CONCAT('%', #{hospitalName}, '%')
AND ds.schedule_date = #{scheduleDate}
ORDER BY ds.schedule_date DESC, ds.time_slot LIMIT #{start}, #{size}
